// Cursor uses (updated_at, id) so pages stay stable when many rows share an
// updated_at. Callers always pass an explicit types filter; to opt out of
// filtering, pass every known type.
func (q *Queries) ListSessionsByBotPaged(ctx context.Context, arg ListSessionsByBotPagedParams) ([]ListSessionsByBotPagedRow, error) {
	rows, err := q.db.Query(ctx, listSessionsByBotPaged,
		arg.BotID,
		arg.Types,
		arg.UseParentSession,
		arg.ParentSessionID,
		arg.UseCursor,
		arg.CursorUpdatedAt,
		arg.CursorID,
		arg.LimitCount,
	)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	var items []ListSessionsByBotPagedRow
	for rows.Next() {
		var i ListSessionsByBotPagedRow
		if err := rows.Scan(
			&i.ID,
			&i.BotID,
			&i.RouteID,
			&i.ChannelType,
			&i.Type,
			&i.Title,
			&i.Metadata,
			&i.DefaultHeadTurnID,
			&i.ForkedFromSessionID,
			&i.ForkedFromTurnID,
			&i.ParentSessionID,
			&i.CreatedByUserID,
			&i.CreatedAt,
			&i.UpdatedAt,
			&i.DeletedAt,
			&i.RouteMetadata,
			&i.RouteConversationType,
		); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

